import { NextResponse } from "next/server";
import { z } from "zod";
import { ensureUserOrg } from "@/lib/auth";
import { getOpenAIClient } from "@/lib/openai";
import { buildMessages } from "@/lib/ai/prompt";

const DISCLAIMER =
  "This information is generated by AI and may not reflect current local regulations. Always verify requirements with the local building authority before starting work.";

const outputSchema = z.object({
  permit_required: z.enum(["Yes", "No", "Likely", "Depends on scope"]),
  permit_required_detail: z.string(),
  permit_type: z.string(),
  local_authority: z.string(),
  relevant_codes: z.array(z.string()),
  inspection_notes: z.string(),
  disclaimer: z.string().default(DISCLAIMER),
});

export type PermitResult = z.infer<typeof outputSchema>;

export async function POST(req: Request) {
  await ensureUserOrg();

  const body = await req.json();
  const { description, address, cityState } = body as {
    description: string;
    address?: string;
    cityState?: string;
  };

  if (!description?.trim()) {
    return NextResponse.json({ error: "description is required" }, { status: 400 });
  }

  const schema = `{
  "permit_required": "Yes | No | Likely | Depends on scope",
  "permit_required_detail": "1-2 sentence explanation",
  "permit_type": "e.g. Building Permit, Mechanical Permit, Electrical Permit, or None",
  "local_authority": "e.g. Local Building Department / City Hall",
  "relevant_codes": ["IRC Section R325 – Radon Control Methods", "..."],
  "inspection_notes": "1-2 sentences on what inspections are typically involved",
  "disclaimer": "${DISCLAIMER}"
}`;

  const messages = buildMessages(
    {
      role: "You are a construction permit assistant for TradeBase, a contractor CRM. Help contractors understand potential permit requirements for their jobs.",
      rules: [
        "Return valid JSON only — no markdown, no prose.",
        "Do not present answers as legal advice.",
        "Be practical and concise.",
        "relevant_codes must be an array of 2–4 specific code references.",
        `Always set disclaimer to exactly: "${DISCLAIMER}"`,
        "Base your answer only on the job description and location provided.",
        "Do not invent or assume details not in the input.",
      ],
      context: {
        job_description: description.trim(),
        ...(address ? { address } : {}),
        ...(cityState ? { location: cityState } : {}),
      },
      task: "Determine permit requirements and provide practical guidance for the job described.",
      schema,
    },
    description.trim()
  );

  const openai = getOpenAIClient();

  let raw: string;
  try {
    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      response_format: { type: "json_object" },
      max_completion_tokens: 1000,
      messages,
    });
    raw = completion.choices[0]?.message?.content ?? "{}";
  } catch (err) {
    console.error("OpenAI error:", err);
    return NextResponse.json({ error: "AI service unavailable" }, { status: 503 });
  }

  let result: PermitResult;
  try {
    result = outputSchema.parse(JSON.parse(raw));
  } catch {
    return NextResponse.json({ error: "Failed to parse AI response" }, { status: 500 });
  }

  return NextResponse.json(result);
}
